// Parse Team Members - Enhanced for Multi-Team & Custom Cohorts + AVATARS
const items = $input.all();
if (!items || items.length === 0) {
  throw new Error('No input data received');
}

const csvData = items[0].json.data || '';
const teamParams = $node['Workflow Parameters1'].json;

console.log('📊 Starting team member parsing...');

// Parse CSV
function parseCSVLine(line) {
  const vals = [];
  let inQuotes = false, current = '';

  for (let i = 0; i < line.length; i++) {
    const c = line[i];
    if (c === '"' && (i === 0 || line[i - 1] !== '\\')) {
      inQuotes = !inQuotes;
      continue;
    }
    if (c === ',' && !inQuotes) {
      vals.push(current);
      current = '';
      continue;
    }
    current += c;
  }
  vals.push(current);
  return vals.map(v => v.trim());
}

const lines = csvData.trim().split(/\r?\n/);
if (lines.length < 2) {
  throw new Error('CSV data appears empty or invalid');
}

const headers = parseCSVLine(lines[0]);

// Find column indices
const nameColIdx = headers.findIndex(h => 
  h.toLowerCase().includes('user') && h.toLowerCase().includes('name')
);

// Find "Team (name)" specifically, not "Team (id)"
const teamColIdx = headers.findIndex(h => 
  h.toLowerCase().includes('team') && 
  h.toLowerCase().includes('name')
);

const emailColIdx = headers.findIndex(h => 
  h.toLowerCase().includes('email')
);
const suspendedColIdx = headers.findIndex(h => 
  h.toLowerCase().includes('suspended')
);

// ⭐ NEW: Find avatar column
const avatarColIdx = headers.findIndex(h => 
  h.toLowerCase().includes('avatar')
);

if (nameColIdx === -1 || teamColIdx === -1 || emailColIdx === -1) {
  throw new Error('Required columns not found in CSV');
}

console.log(`✅ Found columns: Name=${nameColIdx}, Team=${teamColIdx}, Email=${emailColIdx}, Suspended=${suspendedColIdx}, Avatar=${avatarColIdx}`);

// Parse all users
const allUsers = [];
let suspendedCount = 0;

// ⭐ NEW: Build avatar mapping for ALL users
const allUserAvatars = {};

for (let i = 1; i < lines.length; i++) {
  if (!lines[i].trim()) continue;

  const vals = parseCSVLine(lines[i]);
  const isSuspended = suspendedColIdx !== -1 && 
    (vals[suspendedColIdx] || '').toLowerCase() === 'true';

  const userName = vals[nameColIdx] || '';

  // ⭐ NEW: Extract avatar URL if available
  if (avatarColIdx !== -1 && userName) {
    const avatarUrl = (vals[avatarColIdx] || '').trim();
    if (avatarUrl) {
      allUserAvatars[userName] = avatarUrl;
    }
  }

  if (isSuspended) {
    suspendedCount++;
    continue;
  }

  allUsers.push({
    name: userName,
    team: vals[teamColIdx] || '',
    email: vals[emailColIdx] || ''
  });
}

console.log(`👥 Parsed ${allUsers.length} active users (excluded ${suspendedCount} suspended)`);
console.log(`🖼️  Extracted ${Object.keys(allUserAvatars).length} avatar URLs`);

// Build team mappings for each leader
const teamMappings = [];

for (let i = 1; i <= 10; i++) {
  const leaderKey = `leader${i}_name`;
  const emailKey = `leader${i}_email`;
  const teamNamesKey = `leader${i}_team_names`;
  const membersKey = `leader${i}_members`;
  const cohortKey = `leader${i}_cohort_name`;

  if (!teamParams[leaderKey]) continue;

  const leaderName = teamParams[leaderKey].trim();
  const leaderEmail = teamParams[emailKey]?.trim() || '';
  const teamNamesInput = teamParams[teamNamesKey]?.trim() || '';
  const membersInput = teamParams[membersKey]?.trim() || '';
  const cohortName = teamParams[cohortKey]?.trim() || '';

  console.log(`\n👤 Processing leader: ${leaderName}`);

  // Collect all selected users
  let selectedUsers = [];
  let requestedTeamNames = [];
  let isCustomCohort = false;

  // Option 1: Team-based selection
  if (teamNamesInput) {
    requestedTeamNames = teamNamesInput
      .split(',')
      .map(t => t.trim())
      .filter(t => t);

    requestedTeamNames.forEach(teamName => {
      const teamUsers = allUsers.filter(u => 
        u.team.toLowerCase() === teamName.toLowerCase()
      );
      selectedUsers.push(...teamUsers);
      console.log(`  👥 Team "${teamName}": ${teamUsers.length} members`);
    });
  }

  // Option 2: Custom member selection
  if (membersInput) {
    const memberNames = membersInput
      .split(',')
      .map(name => name.trim())
      .filter(name => name);

    const additionalUsers = allUsers.filter(user => {
      const userName = user.name.toLowerCase();
      const alreadyIncluded = selectedUsers.some(u => u.email === user.email);
      return memberNames.some(mn => mn.toLowerCase() === userName) && !alreadyIncluded;
    });

    selectedUsers.push(...additionalUsers);
    console.log(`  🎯 Added ${additionalUsers.length} custom members`);

    if (!teamNamesInput && membersInput) {
      isCustomCohort = true;
    }
  }

  if (selectedUsers.length === 0) {
    console.warn(`  ⚠️ No users found for ${leaderName}`);
    continue;
  }

  // ⭐ NEW: Build avatar mapping for THIS leader's team
  const teamMemberAvatars = {};
  selectedUsers.forEach(user => {
    if (allUserAvatars[user.name]) {
      teamMemberAvatars[user.name] = allUserAvatars[user.name];
    }
  });

  console.log(`  🖼️  ${Object.keys(teamMemberAvatars).length} avatars for this team`);

  // Group users by team
  const teamMap = {};
  const allTeamNames = new Set();

  selectedUsers.forEach(user => {
    const teamName = user.team;
    allTeamNames.add(teamName);

    if (!teamMap[teamName]) {
      teamMap[teamName] = {
        teamName: teamName,
        members: []
      };
    }

    teamMap[teamName].members.push(user);
  });

  // Determine if each team is fully represented
  Object.keys(teamMap).forEach(teamName => {
    const allTeamMembers = allUsers.filter(u => 
      u.team.toLowerCase() === teamName.toLowerCase()
    );
    const selectedTeamMembers = teamMap[teamName].members;

    teamMap[teamName].isFullTeam = selectedTeamMembers.length === allTeamMembers.length;
    teamMap[teamName].totalTeamSize = allTeamMembers.length;

    if (!teamMap[teamName].isFullTeam) {
      console.log(`  📊 ${teamName}: ${selectedTeamMembers.length} of ${allTeamMembers.length} members`);
    }
  });

  // Sort teams alphabetically
  const teams = Object.values(teamMap).sort((a, b) => 
    a.teamName.localeCompare(b.teamName)
  );

  // Build team mapping
  const mapping = {
    leader: leaderName,
    leaderEmail: leaderEmail,
    isCustomCohort: isCustomCohort,
    cohortName: cohortName || (isCustomCohort ? 'Custom Group' : ''),
    requestedTeams: requestedTeamNames,
    teams: teams,

    // Flat lists for backward compatibility
    teamMemberNames: selectedUsers.map(u => u.name),
    teamMemberEmails: selectedUsers.map(u => u.email),
    totalReps: selectedUsers.length,

    // ⭐ NEW: Add avatar mapping
    teamMemberAvatars: teamMemberAvatars
  };

  teamMappings.push(mapping);

  console.log(`  ✅ ${leaderName}: ${selectedUsers.length} reps across ${teams.length} team(s)`);
}

console.log(`\n🎉 Total leaders processed: ${teamMappings.length}`);

// Return SINGLE item with teamMappings array inside
return [{
  json: {
    teamMappings: teamMappings,
    ...items[0].json
  }
}];

// ================================================================
// PREPARE LEADER ITEMS - FIXED VERSION
// This node creates one item per leader, each with the CSV data
// ================================================================

const inputData = $input.item.json;
const csvData = inputData.data;
const teamMappings = $node['Parse Team Members'].json.teamMappings;

// ⭐ FIX: Get ALL quarter data from the input item, including weekStartDate
const quarterData = {
  currentQuarterStart: inputData.currentQuarterStart,
  currentQuarterEnd: inputData.currentQuarterEnd,
  nextQuarterStart: inputData.nextQuarterStart,
  nextQuarterEnd: inputData.nextQuarterEnd,
  currentQuarterLabel: inputData.currentQuarterLabel,
  nextQuarterLabel: inputData.nextQuarterLabel
};

const weekStartDate = inputData.weekStartDate || 'Unknown';

console.log(`👥 Creating ${teamMappings.length} leader items`);
console.log(`📅 Quarter data: ${quarterData.currentQuarterLabel} (${quarterData.currentQuarterStart} to ${quarterData.currentQuarterEnd})`);
console.log(`📅 Week start date: ${weekStartDate}`);

return teamMappings.map(mapping => ({
  json: {
    ...quarterData,
    weekStartDate,
    leader: mapping.leader,
    leaderEmail: mapping.leaderEmail,
    teams: mapping.teams,
    isCustomCohort: mapping.isCustomCohort,
    cohortName: mapping.cohortName,
    requestedTeams: mapping.requestedTeams,
    totalReps: mapping.totalReps,
    teamMemberNames: mapping.teamMemberNames,
    teamMemberEmails: mapping.teamMemberEmails,
    teamMemberAvatars: mapping.teamMemberAvatars || {},
    data: csvData
  }
}));

// ===================== INPUT ======================
const items = $input.all();
const item = items[0].json;

// raw CSV text
const csv = $json.data || "";

if (!csv || typeof csv !== "string") {
    throw new Error("CSV data missing (expected $json.data)");
}

// ✅ FIX: Get ALL fiscal quarter data from Calculate Current Quarter node
const quarterNode = $('Calculate Current Quarter1').first().json;
const currentQuarterStart = quarterNode.currentQuarterStart;
const currentQuarterEnd = quarterNode.currentQuarterEnd;
const currentQuarterLabel = quarterNode.currentQuarterLabel;
const fiscalYear = quarterNode.fiscalYear;
const fiscalQuarter = quarterNode.fiscalQuarter;
const nextQuarterStart = quarterNode.nextQuarterStart;
const nextQuarterEnd = quarterNode.nextQuarterEnd;
const nextQuarterLabel = quarterNode.nextQuarterLabel;
const weekStartDate = quarterNode.weekStartDate;

// Build complete quarterData object
const quarterData = {
  currentQuarterLabel,
  currentQuarterStart,
  currentQuarterEnd,
  fiscalYear,
  fiscalQuarter,
  nextQuarterStart,
  nextQuarterEnd,
  nextQuarterLabel
};

console.log('📅 QuarterData extracted:', quarterData);
console.log('📅 Week Start Date:', weekStartDate);

// Get team info from input
const teamName = item.teamName;
const leader = item.leader;
const leaderEmail = item.leaderEmail;
const teamMemberNames = item.teamMemberNames || [];
const teamMemberEmails = item.teamMemberEmails || [];
const teamMemberAvatars = item.teamMemberAvatars || {};

// 🔧 FIX 1: Extract ALL metadata from input (was missing these!)
const teams = item.teams || [];
const requestedTeams = item.requestedTeams || [];
const totalReps = item.totalReps || 0;
const isCustomCohort = item.isCustomCohort || false;
const cohortName = item.cohortName || '';

console.log(`📅 Processing for ${leader}: ${currentQuarterLabel}`);
console.log(`👥 Team members (${teamMemberNames.length}): ${teamMemberNames.join(', ')}`);
console.log(`📧 Team emails (${teamMemberEmails.length}): ${teamMemberEmails.join(', ')}`);
console.log(`🖼️ Avatars available: ${Object.keys(teamMemberAvatars).length}`);
// 🔧 FIX 2: Log teams array to verify it's present
console.log(`🏢 Teams (${teams.length}): ${teams.map(t => t.teamName).join(', ')}`);

// ======================= CSV PARSER =======================

function parseCSV(text) {
    const rows = [];
    let current = "";
    let inside = false;
    let row = [];

    for (let i = 0; i < text.length; i++) {
        const c = text[i];
        const n = text[i + 1];

        if (c === '"' && inside && n === '"') {
            current += '"';
            i++;
        } else if (c === '"') {
            inside = !inside;
        } else if (c === "," && !inside) {
            row.push(current);
            current = "";
        } else if (c === "\n" && !inside) {
            row.push(current);
            rows.push(row);
            row = [];
            current = "";
        } else if (c !== "\r") {
            current += c;
        }
    }

    if (current.length > 0 || row.length > 0) {
        row.push(current);
        rows.push(row);
    }

    return rows;
}

const rows = parseCSV(csv);
if (!rows || rows.length < 2) {
    throw new Error("CSV parsed but contains no data rows");
}

const headers = rows[0].map(h => h.trim());
const dataRows = rows.slice(1);

console.log(`📋 CSV Headers (${headers.length} columns):`);
headers.forEach((h, i) => console.log(`   ${i}: "${h}"`));
console.log(`📊 Total rows: ${dataRows.length}`);

// Find column indices - CS OWNER (look specifically for the NAME column)
let ownerColIndex = headers.findIndex(h => 
  h === 'CSM Owner (name)' ||           // Exact match first
  h === 'CSM Owner (Name)' ||           // Case variation
  h === 'CSM Owner (User)' ||           // Alternative format
  (h.includes('CSM Owner') && h.includes('name'))  // Contains both
);

// Backup: if we found CSM Owner (id), try to find the (name) version instead
if (ownerColIndex !== -1 && headers[ownerColIndex].includes('(id)')) {
  console.log(`⚠️ Found CSM Owner (id) column, searching for (name) version...`);
  const nameColIdx = headers.findIndex(h => 
    h.includes('CSM Owner') && (h.includes('name') || h.includes('Name'))
  );
  if (nameColIdx !== -1) {
    console.log(`✅ Found CSM Owner (name) at index ${nameColIdx}`);
    ownerColIndex = nameColIdx;
  }
}

// If still not found, try broader search
if (ownerColIndex === -1) {
  console.log(`⚠️ CSM Owner (name) not found, trying broader search...`);
  ownerColIndex = headers.findIndex(h => 
    h.includes('CSM Owner') || 
    h.includes('CS Owner')
  );
  if (ownerColIndex !== -1) {
    console.log(`✅ Found column: "${headers[ownerColIndex]}" at index ${ownerColIndex}`);
  }
}

const stageColIndex = headers.findIndex(h => h === 'Stage' || h === 'ootb_opportunity_current_stage');
const nameColIndex = headers.findIndex(h => h === 'Opportunity Name' || h === 'ootb_opportunity_name');
const amountColIndex = headers.findIndex(h => h === 'Amount (Converted)' || h === 'ootb_opportunity_converted_amount');

console.log(`\n🔍 Column indices: owner=${ownerColIndex} (${headers[ownerColIndex] || 'NOT FOUND'}), stage=${stageColIndex}, name=${nameColIndex}, amount=${amountColIndex}`);

if (ownerColIndex === -1) {
  console.error('⚠️ CS Owner column not found! Available columns:', headers);
  throw new Error('CS Owner column not found in CSV. Check column name.');
}

// ======================= BUILD MATCHING LOOKUP =======================

// Create multiple matching strategies
const matchingStrategies = new Map();

teamMemberNames.forEach((name, idx) => {
    const email = teamMemberEmails[idx];

    // Store original name
    matchingStrategies.set(name.toLowerCase().trim(), name);

    // Store email if available
    if (email) {
        matchingStrategies.set(email.toLowerCase().trim(), name);
    }

    // Store "Last, First" format
    const parts = name.trim().split(' ');
    if (parts.length === 2) {
        const lastFirst = `${parts[1]}, ${parts[0]}`;
        matchingStrategies.set(lastFirst.toLowerCase(), name);

        // Also store "First Last" format explicitly
        matchingStrategies.set(name.toLowerCase().trim(), name);
    }

    // Store just first name for partial matching (as fallback)
    if (parts.length >= 1) {
        const firstName = parts[0].toLowerCase().trim();
        if (!matchingStrategies.has(firstName)) {
            matchingStrategies.set(firstName, name);
        }
    }
});

console.log('\n🔍 Built matching lookup with', matchingStrategies.size, 'variations');

// Function to check if CS Owner is a team member
function isTeamMember(csOwnerValue) {
    if (!csOwnerValue) return false;

    const normalized = csOwnerValue.toLowerCase().trim();

    // Try exact match first
    if (matchingStrategies.has(normalized)) {
        return matchingStrategies.get(normalized);
    }

    // Try partial matches (contains)
    for (const [key, memberName] of matchingStrategies.entries()) {
        if (normalized.includes(key) || key.includes(normalized)) {
            return memberName;
        }
    }

    return null;
}

// ======================= DEBUG: Show CS Owner values =======================
console.log('\n=== CS OWNER VALUES (first 10) ===');
dataRows.slice(0, 10).forEach((row, i) => {
    const ownerValue = row[ownerColIndex];
    const matchedMember = isTeamMember(ownerValue);
    console.log(`${i+1}. "${ownerValue}" → ${matchedMember ? `✅ ${matchedMember}` : '❌ NO MATCH'}`);
});

// Show unique CS Owner values
const uniqueOwners = [...new Set(dataRows.map(r => r[ownerColIndex] || '(empty)'))];
console.log('\n📊 All unique CS Owner values:', uniqueOwners);
console.log('==============================\n');

// ======================= DEBUG: ALL STAGES IN CSV =======================
const allStagesInCSV = new Set();
dataRows.forEach(row => {
    if (stageColIndex !== -1) {
        const stage = row[stageColIndex] || 'Unknown';
        allStagesInCSV.add(stage);
    }
});
console.log('\n=== ALL UNIQUE STAGES IN RAW CSV ===');
console.log([...allStagesInCSV].sort());
console.log('====================================\n');

// Count Closed Won specifically
let closedWonInCSV = 0;
let closedWonFilteredOut = 0;
dataRows.forEach(row => {
    const stage = (row[stageColIndex] || '').toLowerCase();
    if (stage.includes('closed won') || stage === 'closed won') {
        closedWonInCSV++;
        const ownerValue = row[ownerColIndex];
        const matchedMember = isTeamMember(ownerValue);
        if (!matchedMember) {
            closedWonFilteredOut++;
            console.log(`⚠️ CLOSED WON filtered out - CS Owner "${ownerValue}" not in team: ${row[nameColIndex]} ($${row[amountColIndex]})`);
        } else {
            console.log(`✅ CLOSED WON kept - CS Owner "${ownerValue}" → ${matchedMember}: ${row[nameColIndex]} ($${row[amountColIndex]})`);
        }
    }
});
console.log(`\n📊 CLOSED WON SUMMARY: ${closedWonInCSV} total in CSV, ${closedWonFilteredOut} filtered out by team membership\n`);

// ======================= FILTER & OUTPUT =======================

let filteredCount = 0;
let totalCount = 0;
const matchedByOwner = new Map();

const outputItems = dataRows
    .filter(row => {
        totalCount++;

        const ownerValue = row[ownerColIndex];
        const matchedMember = isTeamMember(ownerValue);

        if (matchedMember) {
            filteredCount++;
            // Track which opportunities matched to which team member
            if (!matchedByOwner.has(matchedMember)) {
                matchedByOwner.set(matchedMember, 0);
            }
            matchedByOwner.set(matchedMember, matchedByOwner.get(matchedMember) + 1);
        }

        return matchedMember !== null;
    })
    .map(row => {
        const obj = {
            currentQuarterStart,
            currentQuarterEnd,
            currentQuarterLabel,
            quarterData,
            weekStartDate,  // ⭐ ADDED: Week start date
            teamName,
            leader,
            leaderEmail,
            teamMemberNames,
            teamMemberEmails,
            teamMemberAvatars,
            // 🔧 FIX 3: Include ALL metadata in every output item
            teams,
            requestedTeams,
            totalReps,
            isCustomCohort,
            cohortName
        };

        // Add all CSV columns
        headers.forEach((h, idx) => {
            obj[h] = row[idx] || '';
        });

        // ⭐ CRITICAL FIX: Add the matched team member name
        const ownerValue = row[ownerColIndex];
        const matchedMember = isTeamMember(ownerValue);

        // Store the normalized team member name for grouping
        obj['Matched_Team_Member'] = matchedMember || 'Unknown';

        // Also store in the CSM Owner field for consistency
        if (matchedMember && !obj['CSM Owner (name)']) {
            obj['CSM Owner (name)'] = matchedMember;
        }

        return { json: obj };
    });

console.log(`\n✅ Filtered ${filteredCount} opportunities (from ${totalCount} total) for ${leader}'s team by CS Owner`);
console.log(`📅 Quarter: ${currentQuarterLabel} (${currentQuarterStart} to ${currentQuarterEnd})`);
console.log('📊 Breakdown by team member:');
matchedByOwner.forEach((count, memberName) => {
    console.log(`   ${memberName}: ${count} opportunities`);
});

if (filteredCount === 0) {
    console.warn(`⚠️ WARNING: No opportunities found for team members!`);
    console.warn(`⚠️ Team members: ${teamMemberNames.join(', ')}`);
    console.warn(`⚠️ CS Owner values seen: ${uniqueOwners.slice(0, 10).join(', ')}`);
}

return outputItems;

// ================================================================
// SELECT PRIORITY OPPS & BUILD AI PROMPT - COMPLETE FIX
// ⭐ CHURN ARR for closed lost
// ⭐ Best Case field detection fixed
// ⭐ Percentage calculation fixed (closed lost uses absolute value)
// ⭐ Forecast breakdown uses isClosedWon()/isClosedLost() functions
// ================================================================

const items = $input.all();
const inputData = items[0].json;

const opportunities = inputData.opportunities || [];
const quarterData = inputData.quarterData || {};
const teamMemberNames = inputData.teamMemberNames || [];
const leader = inputData.leader || 'Leader';
const leaderEmail = inputData.leaderEmail || '';
const weekStartDate = inputData.weekStartDate || 'Unknown';
const teamMemberAvatars = inputData.teamMemberAvatars || {};

console.log('📊 Select Priority Opps - Input Data:');
console.log(`  - Opportunities: ${opportunities.length}`);
console.log(`  - Quarter: ${quarterData.currentQuarterLabel}`);
console.log(`  - Week Start: ${weekStartDate}`);
console.log(`  - Leader: ${leader}`);
console.log(`  - Avatars: ${Object.keys(teamMemberAvatars).length}`);

// ========================================
// DEBUG: Show available fields
// ========================================
if (opportunities.length > 0) {
  const sampleOpp = opportunities[0];
  const availableFields = Object.keys(sampleOpp);
  const relevantFields = availableFields.filter(f => 
    f.toLowerCase().includes('stage') || 
    f.toLowerCase().includes('status') ||
    f.toLowerCase().includes('closed') ||
    f.toLowerCase().includes('churn') ||
    f.toLowerCase().includes('engagement')
  );
  console.log('\n🔍 DEBUG: Available fields in opportunities:');
  console.log(`  Relevant fields: ${relevantFields.join(', ')}`);
}

const uniqueStages = [...new Set(opportunities.map(o => o['Stage'] || o['Account Stage'] || ''))];
console.log(`\n📊 Unique stages in data (${uniqueStages.length}):`);
uniqueStages.forEach(stage => console.log(`    - "${stage}"`));

// ========================================
// HELPER FUNCTIONS
// ========================================

function isClosedWon(opp) {
  const stage = String(opp['Stage'] || opp['Account Stage'] || '').toLowerCase().trim();
  const wonStages = [
    'closed won', 'renewed', 'renewal closed', 'expansion closed',
    'retained', 'renewed - expanded', 'renewed - flat',
    'closed - renewed', 'closed - expanded', 'won'
  ];
  return wonStages.some(ws => stage.includes(ws));
}

function isClosedLost(opp) {
  const stage = String(opp['Stage'] || opp['Account Stage'] || '').toLowerCase().trim();
  const lostStages = [
    'closed lost', 'churned', 'churn', 'lost', 'cancelled',
    'canceled', 'downgraded', 'not renewed', 'closed - churned', 'closed - lost'
  ];
  return lostStages.some(ls => stage.includes(ls));
}

function getEngagement(opp) {
  const engagementFields = [
    'Opportunity Engagement Level',
    'Account Engagement Level', 
    'Engagement Level', 
    'Engagement Score',
    'Health Score', 
    'Account Health Score', 
    'Customer Health', 
    'NPS Score'
  ];

  for (const field of engagementFields) {
    const value = parseFloat(opp[field] || 0);
    if (!isNaN(value) && value > 0) {
      return value;
    }
  }
  return 0;
}

function convertTimeToDays(timeStr) {
  if (!timeStr) return 0;
  const parts = String(timeStr).split(':');
  if (parts.length !== 3) return 0;
  const hours = parseInt(parts[0]) || 0;
  const minutes = parseInt(parts[1]) || 0;
  const seconds = parseInt(parts[2]) || 0;
  const totalHours = hours + (minutes / 60) + (seconds / 3600);
  return Math.floor(totalHours / 24);
}

function formatCurrencyShort(value) {
  if (!value || isNaN(value)) return '$0K';
  if (value >= 1_000_000) return '$' + (value / 1_000_000).toFixed(1) + 'M';
  return '$' + Math.round(value / 1_000) + 'K';
}

// ========================================
// INITIALIZE REP SUMMARIES
// ========================================

const repMap = {};
teamMemberNames.forEach(name => {
