    repName: name,
    opportunities: [],
    opportunityCount: 0,
    totalPipelineValue: 0,
    commitAmount: 0,
    commitCount: 0,
    bestCaseAmount: 0,
    closedWonAmount: 0,
    closedWonCount: 0,
    closedLostAmount: 0,
    closedLostCount: 0,
    totalEngagement: 0,
    engagementCount: 0,
    averageEngagement: 0
  };
});

