// PROCESS OPPORTUNITIES
// ========================================

let matchedCount = 0;
let unmatchedCount = 0;
let closedWonFound = 0;
let closedLostFound = 0;
const ownersSeenSet = new Set();
const stagesSeenSet = new Set();

opportunities.forEach(opp => {
  const ownerName = opp['CSM Owner (name)'] || opp['Opportunity Owner (name)'] || '';

  ownersSeenSet.add(ownerName);
  stagesSeenSet.add(opp['Stage'] || opp['Account Stage'] || '');

  if (repMap[ownerName]) {
    matchedCount++;

    const amount = parseFloat(opp['Amount (Converted)'] || opp['Amount'] || 0) || 0;
    const engagement = getEngagement(opp);
    const isCommit = String(opp['Rep Forecast Category'] || '').toLowerCase().includes('commit');

    // ⭐ FIX #1: Check all forecast category fields including API field
    const category = String(
      opp['CS Forecast Category'] || 
      opp['Rep Forecast Category'] || 
      opp['Forecast Category'] ||  // ⭐ NEW - from ootb_opportunity_forecast_category
      ''
    ).toUpperCase();
    const isBestCase = category.includes('BEST CASE') || category.includes('BEST');

    const wonStatus = isClosedWon(opp);
    const lostStatus = isClosedLost(opp);

    // Store opportunity for priority selection
    repMap[ownerName].opportunities.push(opp);
    repMap[ownerName].opportunityCount++;

    // Check commit FIRST (for ALL opportunities)
    if (isCommit) {
      repMap[ownerName].commitAmount += amount;
      repMap[ownerName].commitCount++;
    }

    // Track Best Case (open opps only)
    if (isBestCase && !wonStatus && !lostStatus) {
      repMap[ownerName].bestCaseAmount += amount;
      console.log(`  🎯 Best Case: ${opp['Account Name']} - $${Math.round(amount/1000)}K (Category: ${category})`);
    }

    if (wonStatus) {
      repMap[ownerName].closedWonAmount += amount;
      repMap[ownerName].closedWonCount++;
      closedWonFound++;
    } else if (lostStatus) {
      // ⭐ USE CHURN ARR FOR CLOSED LOST
      const churnAmount = parseFloat(opp['Churn ARR'] || 0) || 0;
      repMap[ownerName].closedLostAmount += churnAmount;
      repMap[ownerName].closedLostCount++;
      closedLostFound++;

      if (churnAmount > 0) {
        console.log(`  💰 Closed Lost: ${opp['Account Name']} - Churn ARR: $${Math.round(churnAmount/1000)}K`);
      }
    } else {
      // Open opportunity
      repMap[ownerName].totalPipelineValue += amount;
    }

    if (engagement > 0) {
      repMap[ownerName].totalEngagement += engagement;
      repMap[ownerName].engagementCount++;
    }
  } else {
    unmatchedCount++;
  }
});

