// ========================================
// PRIORITY SELECTION
// ========================================

const priorityAccounts = [];

Object.values(repMap).forEach(rep => {
  if (rep.opportunities.length === 0) return;

  // FILTER TO OPEN OPPORTUNITIES ONLY (for top value and at-risk)
  const openOpps = rep.opportunities.filter(opp => {
    return !isClosedWon(opp) && !isClosedLost(opp);
  });

  // TOP 2 BY VALUE (from open opportunities)
  if (openOpps.length > 0) {
    const sortedByValue = [...openOpps].sort((a, b) => {
      const aAmt = parseFloat(a['Amount (Converted)'] || a['Amount'] || 0) || 0;
      const bAmt = parseFloat(b['Amount (Converted)'] || b['Amount'] || 0) || 0;
      return bAmt - aAmt;
    });

    const top2 = sortedByValue.slice(0, 2);
    const top2Ids = new Set(top2.map(o => o['ID']));

    top2.forEach(opp => {
      priorityAccounts.push({
        accountName: opp['Account Name'] || 'Unknown Account',
        opportunityName: opp['Opportunity Name'] || 'Unknown Opportunity',
        repName: rep.repName,
        amount: parseFloat(opp['Amount (Converted)'] || opp['Amount'] || 0) || 0,
        stage: opp['Stage'] || opp['Account Stage'] || 'Unknown',
        engagement: getEngagement(opp),
        daysInStage: convertTimeToDays(opp['Days in Stage']),
        closeDate: opp['Close Date'] || '',
        selectionReason: 'Top by Value',
        peopleaiId: parseInt(opp['ootb_opportunity_people_internal_id'] || opp['peopleai_opportunity_id']) || null
      });
    });

    // AT-RISK OPPORTUNITIES (TOP 2 from open opportunities)
    const atRiskOpps = openOpps.filter(opp => {
      if (top2Ids.has(opp['ID'])) return false;

      const engagement = getEngagement(opp);
      const daysInStage = convertTimeToDays(opp['Days in Stage']);
      const amount = parseFloat(opp['Amount (Converted)'] || opp['Amount'] || 0) || 0;
      const closeDate = new Date(opp['Close Date'] || '2099-01-01');
      const daysUntilClose = Math.ceil((closeDate - new Date()) / (1000 * 60 * 60 * 24));

      const reasons = [];
      if (engagement > 0 && engagement < 30) reasons.push('Low Engagement');
      if (daysInStage > 60) reasons.push('Stalled');
      if (daysUntilClose > 0 && daysUntilClose < 30) reasons.push('Closing Soon');
      if (amount > 100000 && engagement < 40) reasons.push('Large Deal at Risk');

      if (reasons.length > 0) {
        opp.riskReasons = reasons;
        opp.riskScore = reasons.length;
        return true;
      }
      return false;
    });

    atRiskOpps.sort((a, b) => {
      if (b.riskScore !== a.riskScore) return b.riskScore - a.riskScore;
      const aAmt = parseFloat(a['Amount (Converted)'] || a['Amount'] || 0) || 0;
      const bAmt = parseFloat(b['Amount (Converted)'] || b['Amount'] || 0) || 0;
      return bAmt - aAmt;
    });

    atRiskOpps.slice(0, 2).forEach(opp => {
      priorityAccounts.push({
        accountName: opp['Account Name'] || 'Unknown Account',
        opportunityName: opp['Opportunity Name'] || 'Unknown Opportunity',
        repName: rep.repName,
        amount: parseFloat(opp['Amount (Converted)'] || opp['Amount'] || 0) || 0,
        stage: opp['Stage'] || opp['Account Stage'] || 'Unknown',
        engagement: getEngagement(opp),
        daysInStage: convertTimeToDays(opp['Days in Stage']),
        closeDate: opp['Close Date'] || '',
        selectionReason: `At Risk: ${opp.riskReasons.join(', ')}`,
        peopleaiId: parseInt(opp['ootb_opportunity_people_internal_id'] || opp['peopleai_opportunity_id']) || null
      });
    });
  }

  // RECENT CLOSED LOST (for lessons learned)
  const closedLostOpps = rep.opportunities.filter(opp => isClosedLost(opp));

  if (closedLostOpps.length > 0) {
    closedLostOpps.sort((a, b) => {
      const aDate = new Date(a['Close Date'] || '1900-01-01');
      const bDate = new Date(b['Close Date'] || '1900-01-01');
      return bDate - aDate;
    });

    closedLostOpps.slice(0, 1).forEach(opp => {
      const churnAmount = parseFloat(opp['Churn ARR'] || 0) || 0;

      priorityAccounts.push({
        accountName: opp['Account Name'] || 'Unknown Account',
        opportunityName: opp['Opportunity Name'] || 'Unknown Opportunity',
        repName: rep.repName,
        amount: churnAmount,
        stage: opp['Stage'] || opp['Account Stage'] || 'Unknown',
        engagement: getEngagement(opp),
        daysInStage: convertTimeToDays(opp['Days in Stage']),
        closeDate: opp['Close Date'] || '',
        selectionReason: 'Recent Closed Lost - Lessons Learned',
        peopleaiId: parseInt(opp['ootb_opportunity_people_internal_id'] || opp['peopleai_opportunity_id']) || null
      });
    });
  }
});

