console.log('\n📊 Calculating Forecast Breakdown by CS Forecast Category...');

const forecastBreakdown = {
  'CLOSED WON': { count: 0, amount: 0 },
  'COMMIT': { count: 0, amount: 0 },
  'BEST CASE': { count: 0, amount: 0 },
  'PIPELINE': { count: 0, amount: 0 },
  'CLOSED LOST': { count: 0, amount: 0 }
};

const seenCategories = new Set();

let oppProcessed = 0;
Object.values(repMap).forEach(repData => {
  repData.opportunities.forEach(opp => {
    oppProcessed++;

    const rawCategory = 
      opp['CS Forecast Category'] || 
      opp['CSM Forecast Category'] ||
      opp['Forecast Category'] ||
      opp['Rep Forecast Category'] ||
      opp['Stage'] ||
      '';

    seenCategories.add(rawCategory);

    let amount = parseFloat(opp['Amount (Converted)'] || opp['Amount'] || 0) || 0;
    let mappedCategory = 'PIPELINE';

    // ⭐ FIX #3: USE HELPER FUNCTIONS INSTEAD OF STRING MATCHING
    if (isClosedWon(opp)) {
      mappedCategory = 'CLOSED WON';
    } else if (isClosedLost(opp)) {
      mappedCategory = 'CLOSED LOST';
      // ⭐ USE CHURN ARR FOR CLOSED LOST
      amount = parseFloat(opp['Churn ARR'] || 0) || 0;
    } else {
      // For open opportunities, check forecast category
      const category = rawCategory.toString().toUpperCase().trim();

      if (category.includes('COMMIT')) {
        mappedCategory = 'COMMIT';
      } else if (category.includes('BEST CASE') || category.includes('BEST')) {
        mappedCategory = 'BEST CASE';
      } else if (category.includes('PIPELINE')) {
        mappedCategory = 'PIPELINE';
      }
    }

    forecastBreakdown[mappedCategory].count++;
    forecastBreakdown[mappedCategory].amount += amount;
  });
});

console.log(`📋 Processed ${oppProcessed} opportunities`);
console.log('📋 Unique categories seen:', Array.from(seenCategories));

// ⭐ FIX #2: Use absolute value of CLOSED LOST for percentage base
const totalPipelineAmount = 
  forecastBreakdown['CLOSED WON'].amount +
  forecastBreakdown['COMMIT'].amount +
  forecastBreakdown['BEST CASE'].amount +
  forecastBreakdown['PIPELINE'].amount +
  Math.abs(forecastBreakdown['CLOSED LOST'].amount);

console.log(`💰 Total Pipeline Amount for % calc: $${(totalPipelineAmount/1000000).toFixed(2)}M`);

const forecastBreakdownWithPercent = {};
Object.keys(forecastBreakdown).forEach(category => {
  const data = forecastBreakdown[category];

  // ⭐ For CLOSED LOST, use absolute value in percentage but keep amount negative
  const amountForPercentage = category === 'CLOSED LOST' 
    ? Math.abs(data.amount) 
    : data.amount;

  const percentage = totalPipelineAmount > 0 
    ? (amountForPercentage / totalPipelineAmount * 100) 
    : 0;

  forecastBreakdownWithPercent[category] = {
    count: data.count,
    amount: data.amount,  // Keep actual amount (negative for CLOSED LOST)
    percentage: category === 'CLOSED LOST' ? -Math.abs(percentage) : percentage
  };
});

console.log('📊 Forecast Breakdown:');
Object.keys(forecastBreakdownWithPercent).forEach(category => {
  const data = forecastBreakdownWithPercent[category];
  console.log(`  ${category}: ${data.count} deals, $${(Math.abs(data.amount)/1000000).toFixed(2)}M (${data.percentage.toFixed(1)}%)`);
});
