console.log(`  Total Closed Won: $${(totalClosedWon/1000000).toFixed(2)}M (${totalClosedWonCount} deals)`);
console.log(`  Total Pipeline: $${(teamMetrics.totalPipeline/1000000).toFixed(2)}M`);
console.log(`  Total Commit: $${(teamMetrics.totalCommit/1000000).toFixed(2)}M`);
console.log(`  Total Best Case: $${(totalBestCase/1000000).toFixed(2)}M`);
console.log(`  Total Closed Lost: $${(Math.abs(totalClosedLost)/1000000).toFixed(2)}M`);
console.log(`  Avg Engagement: ${teamMetrics.averageEngagement.toFixed(1)}% (kept for analysis, removed from table)`);

// ========================================
// EXTRACT AI SECTIONS
// ========================================

function extractSection(pattern) {
  const match = aiOutput.match(pattern);
  return match ? match[1].trim() : '';
}

const executiveSummary = extractSection(/### 1\.\s*Executive Summary[\s\S]*?\n\n([\s\S]*?)(?=\n---|\n###|\n##|$)/i) || 
                        extractSection(/Executive Summary[\s\S]*?\n\n([\s\S]*?)(?=\n---|\n###|\n##|$)/i) ||
                        'Overall team performance is on track for the quarter.';

const topIssues = extractSection(/### 2\.\s*Top 3 Team Issues[\s\S]*?\n\n([\s\S]*?)(?=\n---|\n###|\n##|$)/i) ||
                 extractSection(/Top 3 Team Issues[\s\S]*?\n\n([\s\S]*?)(?=\n---|\n###|\n##|$)/i) ||
                 '- Monitor engagement levels\n- Track pipeline progress\n- Ensure customer success';

const weeklyFocus = extractSection(/### 3\.\s*This Week'?s? Focus[\s\S]*?\n\n([\s\S]*?)(?=\n---|\n###|\n##|$)/i) ||
                   extractSection(/This Week'?s? Focus[\s\S]*?\n\n([\s\S]*?)(?=\n---|\n###|\n##|$)/i) ||
                   '- Review top accounts\n- Address at-risk situations\n- Plan customer engagement';

const repCoaching = extractSection(/### 4\.\s*CSM Coaching[\s\S]*?\n\n([\s\S]*?)(?=\n---|\n##|$)/i) ||
                   extractSection(/CSM Coaching[\s\S]*?\n\n([\s\S]*?)(?=\n---|\n##|$)/i) ||
                   aiOutput.substring(aiOutput.indexOf('CSM Coaching') + 12) || '';

// ========================================
// FORMAT MARKDOWN TO HTML
// ========================================

function markdownToHtml(text) {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>')
    .replace(/\*([^*]+)\*/g, '<em>$1</em>')
    .replace(/^- (.+)$/gm, '<li>$1</li>')
    .replace(/(<li>.*<\/li>)/s, '<ul style="margin:8px 0;padding-left:24px;">$1</ul>')
    .replace(/\n\n/g, '</p><p style="margin:12px 0;line-height:1.6;">')
    .replace(/^(.+)$/gm, function(match) {
      if (!match.startsWith('<') && match.trim().length > 0) {
        return '<p style="margin:12px 0;line-height:1.6;">' + match + '</p>';
      }
      return match;
    });
}

// ========================================
// MINIMALIST WITH ICON ACCENTS - CSM COACHING
// ========================================

function parseRepCoachingSections(coachingText) {
  const sections = [];

  // Match pattern: **Name** (stats) followed by bullet points
  const repPattern = /\*\*([^*]+)\*\*\s*\(([^)]+)\)([\s\S]*?)(?=\*\*[^*]+\*\*\s*\(|$)/g;

  let match;
  while ((match = repPattern.exec(coachingText)) !== null) {
    const repName = match[1].trim();
    const stats = match[2].trim();
    const content = match[3].trim();

    // Parse stats
    const pipelineMatch = stats.match(/\$([^\s,]+)\s*pipeline/i);
    const wonMatch = stats.match(/\$([^\s,]+)\s*won/i);
    const engMatch = stats.match(/(\d+)%\s*eng/i);

    const pipeline = pipelineMatch ? pipelineMatch[1] : '0K';
    const won = wonMatch ? wonMatch[1] : '0K';
    const engagement = engMatch ? engMatch[1] + '%' : '0%';

    // Parse bullet points
    const topAccountMatch = content.match(/[•\-*]\s*\*\*Top account\*\*:\s*([^\n]+)/i);
    const keyIssueMatch = content.match(/[•\-*]\s*\*\*Key issue\*\*:\s*([^\n]+)/i);
    const actionMatch = content.match(/[•\-*]\s*\*\*Action\*\*:\s*([^\n]+)/i);

    const topAccount = topAccountMatch ? topAccountMatch[1].trim() : 'No top account specified';
    const keyIssue = keyIssueMatch ? keyIssueMatch[1].trim() : 'No key issue specified';
    const action = actionMatch ? actionMatch[1].trim() : 'No action specified';

    sections.push({
      repName,
      pipeline,
      won,
      engagement,
      topAccount,
      keyIssue,
      action
    });
  }

  console.log(`📋 Parsed ${sections.length} CSM coaching sections for Minimalist Icon Accents layout`);
  return sections;
}

function formatCSMCoachingMinimalist(text) {
  if (!text) return '<p style="color:#6b7280;font-style:italic;">No CSM coaching available.</p>';

  const sections = parseRepCoachingSections(text);

