          </div>
        </div>

        <!-- Content Rows -->
        <div style="display:flex;align-items:start;margin-bottom:8px;">
          <div style="width:32px;height:32px;border-radius:6px;background:#dbeafe;display:flex;align-items:center;justify-content:center;margin-right:10px;flex-shrink:0;">
            <span style="font-size:16px;">🎯</span>
          </div>
          <div>
            <div style="font-size:11px;font-weight:700;color:#3b82f6;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:4px;">Top Account</div>
            <div style="font-size:13px;color:#374151;line-height:1.5;">${section.topAccount}</div>
          </div>
        </div>

        <div style="display:flex;align-items:start;margin-bottom:8px;">
          <div style="width:32px;height:32px;border-radius:6px;background:#fee2e2;display:flex;align-items:center;justify-content:center;margin-right:10px;flex-shrink:0;">
