            <div style="font-size:13px;color:#374151;line-height:1.5;">${section.action}</div>
          </div>
        </div>
      </div>
    `;
  }).join('');
}

const executiveSummaryHTML = markdownToHtml(executiveSummary);
const topIssuesHTML = markdownToHtml(topIssues);
