const now = new Date();
const currentMonth = now.getMonth(); // 0-indexed
const currentYear = now.getFullYear();
let fiscalYear, fiscalQuarter;

// Fiscal calendar logic (Feb-Jan)
if (currentMonth === 0) {
  fiscalYear = currentYear;
  fiscalQuarter = 4;
} else if (currentMonth >= 1 && currentMonth <= 3) {
  fiscalYear = currentYear + 1;
  fiscalQuarter = 1;
} else if (currentMonth >= 4 && currentMonth <= 6) {
  fiscalYear = currentYear + 1;
  fiscalQuarter = 2;
} else if (currentMonth >= 7 && currentMonth <= 9) {
  fiscalYear = currentYear + 1;
  fiscalQuarter = 3;
} else {
  fiscalYear = currentYear + 1;
  fiscalQuarter = 4;
}

// Helper function to calculate quarter dates
function getQuarterDates(year, quarter) {
  let startMonth, endMonth;

  if (quarter === 1) {
    startMonth = 1;  // February
    endMonth = 3;    // April
  } else if (quarter === 2) {
    startMonth = 4;  // May
    endMonth = 6;    // July
  } else if (quarter === 3) {
    startMonth = 7;  // August
    endMonth = 9;    // October
  } else {
    startMonth = 10; // November
    endMonth = 0;    // January (next year)
  }

  const startYear = (quarter === 4) ? year - 1 : year;
  const start = new Date(Date.UTC(startYear, startMonth, 1, 0, 0, 0, 0));

  const endYear = (endMonth === 0) ? year : startYear;
  const endMonthDate = endMonth === 0 ? 1 : endMonth + 1;
  const lastDay = new Date(Date.UTC(endYear, endMonthDate, 0)).getDate();
  const end = new Date(Date.UTC(endYear, endMonth === 0 ? 0 : endMonth, lastDay, 23, 59, 59, 999));

  return { start, end };
}

// Calculate CURRENT quarter dates
const currentQuarter = getQuarterDates(fiscalYear, fiscalQuarter);
const currentQuarterLabel = `FY${String(fiscalYear).slice(-2)}Q${fiscalQuarter}`;

// Calculate NEXT quarter dates
let nextFiscalYear = fiscalYear;
let nextFiscalQuarter = fiscalQuarter + 1;
if (nextFiscalQuarter > 4) {
  nextFiscalQuarter = 1;
  nextFiscalYear++;
}
const nextQuarter = getQuarterDates(nextFiscalYear, nextFiscalQuarter);
const nextQuarterLabel = `FY${String(nextFiscalYear).slice(-2)}Q${nextFiscalQuarter}`;

// Calculate week start date (Monday of current week)
const today = new Date();
const dayOfWeek = today.getDay();
const daysToMonday = (dayOfWeek === 0) ? -6 : 1 - dayOfWeek; // Sunday = 0, Monday = 1
const monday = new Date(today);
monday.setDate(today.getDate() + daysToMonday);

const weekStartDate = monday.toLocaleDateString('en-US', { 
  month: 'short', 
  day: 'numeric', 
  year: 'numeric' 
});

console.log('📅 Current Quarter:', currentQuarterLabel);
console.log('📅 Current Start:', currentQuarter.start.toISOString());
console.log('📅 Current End:', currentQuarter.end.toISOString());
console.log('📅 Next Quarter:', nextQuarterLabel);
console.log('📅 Next Start:', nextQuarter.start.toISOString());
console.log('📅 Next End:', nextQuarter.end.toISOString());
console.log('📅 Week Start (Monday):', weekStartDate);

return [{
  json: {
    // Current quarter
    currentQuarterLabel,
    fiscalYear,
    fiscalQuarter,
    quarterStartISO: currentQuarter.start.toISOString().split('T')[0],
    quarterEndISO: currentQuarter.end.toISOString().split('T')[0],
    quarterStartTimestamp: currentQuarter.start.getTime(),
    quarterEndTimestamp: currentQuarter.end.getTime(),
    currentQuarterStart: currentQuarter.start.toISOString(),
    currentQuarterEnd: currentQuarter.end.toISOString(),

    // Next quarter
    nextQuarterLabel,
    nextQuarterStart: nextQuarter.start.toISOString(),
    nextQuarterEnd: nextQuarter.end.toISOString(),

    // Week start
    weekStartDate,

    // Pass through input
    ...$input.all()[0].json
  }
}];

// Group Opportunities by Team - FIXED to include quarterData
const items = $input.all();

console.log('📊 Group Opportunities by Team - Starting...');
console.log('📥 Received', items.length, 'items');

if (items.length === 0) {
  throw new Error('No input items received');
}

// First item contains team metadata (passed from loop)

const firstItem = items[0].json;

// ADD THESE DEBUG LINES:
console.log('🔍 DEBUG: ALL firstItem fields:', JSON.stringify(firstItem, null, 2));
console.log('📅 weekStartDate?', firstItem.weekStartDate);
console.log('📅 Week keys:', Object.keys(firstItem).filter(k => k.toLowerCase().includes('week')));

console.log('👤 Leader:', firstItem.leader);
console.log('🏢 Teams:', firstItem.teams ? firstItem.teams.length : 'NOT FOUND');
console.log('👥 Team members:', firstItem.teamMemberNames ? firstItem.teamMemberNames.length : 0);

// Extract team data
const teamData = {
  leader: firstItem.leader,
  leaderEmail: firstItem.leaderEmail,
  teams: firstItem.teams || [],
  isCustomCohort: firstItem.isCustomCohort || false,
  cohortName: firstItem.cohortName || '',
  requestedTeams: firstItem.requestedTeams || [],
  totalReps: firstItem.totalReps || 0,
  teamMemberNames: firstItem.teamMemberNames || [],
  teamMemberEmails: firstItem.teamMemberEmails || [],
  teamMemberAvatars: firstItem.teamMemberAvatars || {},
  // ✅ FIX: Add quarterData
  quarterData: {
    currentQuarterStart: firstItem.currentQuarterStart,
    currentQuarterEnd: firstItem.currentQuarterEnd,
    nextQuarterStart: firstItem.nextQuarterStart,
    nextQuarterEnd: firstItem.nextQuarterEnd,
    currentQuarterLabel: firstItem.currentQuarterLabel,
    nextQuarterLabel: firstItem.nextQuarterLabel
  },
  weekStartDate: firstItem.weekStartDate
};

// 🔧 FIX: All items ARE the opportunities (already parsed from Filter node)
const opportunities = items.map(item => item.json);

console.log('💼 Processing', opportunities.length, 'opportunities');

// Build rep-to-team mapping from teams array
const repTeamMap = {};
teamData.teams.forEach(team => {
  team.members.forEach(member => {
    repTeamMap[member.name] = {
      teamName: team.teamName,
      isFullTeam: team.isFullTeam,
      totalTeamSize: team.totalTeamSize
    };
  });
});

console.log('🗺️ Rep-to-team mapping:', Object.keys(repTeamMap).length, 'reps');

// Find owner column name (it varies)
const sampleOpp = opportunities[0];
const possibleOwnerFields = [
  'CSM Owner (name)',
  'Opportunity Owner (name)',
  'Matched_Team_Member'
];

let ownerField = possibleOwnerFields.find(field => sampleOpp[field] !== undefined);

if (!ownerField) {
  console.log('⚠️ Could not find owner field. Available fields:', Object.keys(sampleOpp));
  ownerField = 'CSM Owner (name)'; // fallback
}

console.log('👤 Using owner field:', ownerField);

// Enrich opportunities with team info
const enrichedOpportunities = opportunities.map(opp => {
  const ownerName = opp[ownerField] || opp['Matched_Team_Member'];
  const teamInfo = repTeamMap[ownerName] || {
    teamName: 'Unknown Team',
    isFullTeam: false,
    totalTeamSize: 0
  };

  return {
    ...opp,
    _teamName: teamInfo.teamName,
    _ownerName: ownerName,
    _isFullTeam: teamInfo.isFullTeam,
    _totalTeamSize: teamInfo.totalTeamSize
  };
});

// Group opportunities by team
const opportunitiesByTeam = {};
enrichedOpportunities.forEach(opp => {
  const teamName = opp._teamName;
  if (!opportunitiesByTeam[teamName]) {
    opportunitiesByTeam[teamName] = {
      teamName: teamName,
      opportunities: [],
      count: 0,
      totalValue: 0
    };
  }

  opportunitiesByTeam[teamName].opportunities.push(opp);
  opportunitiesByTeam[teamName].count++;

  // Sum value - try multiple field names
  const amountStr = opp['Amount (Converted)'] || 
                    opp['ootb_opportunity_converted_amount'] || 
                    opp['Amount'] || 
                    '0';
  const amount = parseFloat(amountStr) || 0;
  opportunitiesByTeam[teamName].totalValue += amount;
});

console.log('📊 Opportunities grouped into', Object.keys(opportunitiesByTeam).length, 'teams');

// Log team summaries
Object.values(opportunitiesByTeam).forEach(teamGroup => {
  console.log(`  🏢 ${teamGroup.teamName}: ${teamGroup.count} opps, $${Math.round(teamGroup.totalValue).toLocaleString()}`);
});

console.log('\n✅ Grouping complete. Total opportunities:', enrichedOpportunities.length);

return [{
  json: {
    ...teamData,
    opportunities: enrichedOpportunities,
    opportunitiesByTeam: opportunitiesByTeam,
    totalOpportunities: enrichedOpportunities.length
  }
}];
